"""THERMODYNAMICS OF ATTENTION- PHASE DIAGRAMS"""import osimport mathimport pickleimport randomimport multiprocessingimport scipy.ioimport numpy as npimport torchimport torch.nn as nnimport torch.nn.functional as Fimport torch.optim as optimfrom tqdm import tqdmfrom torch.utils.data import DataLoader, Subsetfrom torchvision import datasets, transforms# ============================================================# 0. OPTIONAL DEPENDENCY (OrganAMNIST)# ============================================================try:    from medmnist import OrganAMNISTexcept Exception:    OrganAMNIST = None# ============================================================# 1. CONFIGURATION (SELECT DATASET HERE)# ============================================================DATASET_NAME = "CIFAR10"  # "MNIST", "CIFAR10", "OrganAMNIST"EXPERIMENT_NAME = f"{DATASET_NAME.lower()}_thermo"try:    SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))except NameError:    SCRIPT_DIR = os.getcwd()SAVE_DIR = os.path.join(SCRIPT_DIR, f"results_{EXPERIMENT_NAME}")os.makedirs(SAVE_DIR, exist_ok=True)# GridTEMPS = np.geomspace(0.01, 10.0, 25).tolist()WEIGHT_DECAYS = np.geomspace(1e-6, 1.0, 25).tolist()BASE_CONFIG = {    "d_model": 64,    "n_head": 4,    "n_layer": 2,    "lr": 1e-3,    "epochs": 15,    "batch_size": 256,    "base_seed": 42,    "num_seeds": 5,    "pool_workers": max(1, multiprocessing.cpu_count() - 1),    "num_loader_workers": 0,   # we keep 0 inside pool workers to avoid process explosion    "train_limit": 4000,       # set None to use full dataset    "test_limit": 4000,    "mi_pseudocount": 1e-8,    # stabilizes MI when marginals are tiny}if DATASET_NAME == "MNIST":    CONFIG = {        **BASE_CONFIG,        "img_size": 28,        "patch_size": 4,        "in_channels": 1,        "num_classes": 10,    }elif DATASET_NAME == "CIFAR10":    CONFIG = {        **BASE_CONFIG,        "img_size": 32,        "patch_size": 4,        "in_channels": 3,        "num_classes": 10,    }elif DATASET_NAME == "OrganAMNIST":  # <--- NEW OPTION    CONFIG = BASE_CONFIG | {        "img_size": 28,         "patch_size": 4,         "in_channels": 1,   # Grayscale        "num_classes": 11   # 11 Organ categories    }else:    raise ValueError(f"Unknown DATASET_NAME: {DATASET_NAME}")DATA_CACHE = {}# ============================================================# 2. MODEL# ============================================================class ThermalAttention(nn.Module):    def __init__(self, d_model: int, n_head: int):        super().__init__()        if d_model % n_head != 0:            raise ValueError("d_model must be divisible by n_head")        self.head_dim = d_model // n_head        self.n_head = n_head        self.qkv = nn.Linear(d_model, 3 * d_model, bias=False)        self.proj = nn.Linear(d_model, d_model, bias=False)        self.q_norm = nn.LayerNorm(self.head_dim)        self.k_norm = nn.LayerNorm(self.head_dim)        # Per-forward cached stats (per sample)        self.batch_S_raw = None   # nats        self.batch_S_norm = None  # [0,1]        self.batch_E_var = None   # energy variance proxy    def forward(self, x: torch.Tensor, T: float = 1.0, track_stats: bool = False) -> torch.Tensor:        if T <= 0:            raise ValueError("Temperature T must be > 0")        B, S, C = x.shape        qkv = self.qkv(x).reshape(B, S, 3, self.n_head, self.head_dim).permute(2, 0, 3, 1, 4)        q, k, v = self.q_norm(qkv[0]), self.k_norm(qkv[1]), qkv[2]        raw_dot_prod = (q @ k.transpose(-2, -1)) / math.sqrt(self.head_dim)  # [B,H,S,S]        scaled_logits = raw_dot_prod / T        scaled_logits = scaled_logits - scaled_logits.amax(dim=-1, keepdim=True)        att = F.softmax(scaled_logits, dim=-1)        if track_stats:            n_keys = att.size(-1)            # Entropy in nats and normalized entropy            S_raw = -(att * torch.log(att + 1e-12)).sum(dim=-1)               # [B,H,S]            S_norm = S_raw / math.log(n_keys)                                  # [B,H,S]            self.batch_S_raw = S_raw.mean(dim=(1, 2))                           # [B]            self.batch_S_norm = S_norm.mean(dim=(1, 2))                         # [B]            # Energy variance proxy (Var_p[E])            E = -raw_dot_prod                                                   # [B,H,S,S]            E_mean = (att * E).sum(dim=-1)                                      # [B,H,S]            E2_mean = (att * (E**2)).sum(dim=-1)                                # [B,H,S]            var_per_query = E2_mean - (E_mean ** 2)                             # [B,H,S]            self.batch_E_var = var_per_query.mean(dim=(1, 2))                   # [B]        else:            # avoid accidental reuse if someone refactors later            self.batch_S_raw = None            self.batch_S_norm = None            self.batch_E_var = None        out = (att @ v).transpose(1, 2).reshape(B, S, C)        return self.proj(out)class ThermodynamicViT(nn.Module):    def __init__(self, config: dict):        super().__init__()        self.patch_size = config["patch_size"]        self.n_patches = (config["img_size"] // self.patch_size) ** 2        self.patch_embed = nn.Linear(config["in_channels"] * (self.patch_size ** 2), config["d_model"])        self.pos_emb = nn.Parameter(torch.zeros(1, self.n_patches, config["d_model"]))        self.blocks = nn.ModuleList([            nn.ModuleDict({                "attn": ThermalAttention(config["d_model"], config["n_head"]),                "ln1": nn.LayerNorm(config["d_model"]),                "mlp": nn.Sequential(                    nn.Linear(config["d_model"], 4 * config["d_model"]),                    nn.GELU(),                    nn.Linear(4 * config["d_model"], config["d_model"]),                ),                "ln2": nn.LayerNorm(config["d_model"]),            }) for _ in range(config["n_layer"])        ])        self.ln_f = nn.LayerNorm(config["d_model"])        self.head = nn.Linear(config["d_model"], config["num_classes"])    def forward(self, x: torch.Tensor, T: float = 1.0, track_stats: bool = False) -> torch.Tensor:        x = F.unfold(x, kernel_size=self.patch_size, stride=self.patch_size).transpose(1, 2)        x = self.patch_embed(x) + self.pos_emb        for b in self.blocks:            x = x + b["attn"](b["ln1"](x), T=T, track_stats=track_stats)            x = x + b["mlp"](b["ln2"](x))        x = self.ln_f(x).mean(dim=1)        return self.head(x)# ============================================================# 3. DATA AND SEEDING# ============================================================def _stratified_subset(dataset, limit: int, seed: int, num_classes: int):    if limit is None or limit >= len(dataset):        return dataset if not isinstance(dataset, Subset) else dataset    # Build label -> indices map    rng = np.random.default_rng(seed)    indices_by_class = [[] for _ in range(num_classes)]    for idx in range(len(dataset)):        _, y = dataset[idx]        if isinstance(y, torch.Tensor):            yv = int(y.item()) if y.numel() == 1 else int(y.view(-1)[0].item())        else:            yv = int(y)        indices_by_class[yv].append(idx)    # Shuffle each class list    for c in range(num_classes):        rng.shuffle(indices_by_class[c])    # Round-robin selection to fill limit    chosen = []    ptrs = [0] * num_classes    while len(chosen) < limit:        made_progress = False        for c in range(num_classes):            if len(chosen) >= limit:                break            if ptrs[c] < len(indices_by_class[c]):                chosen.append(indices_by_class[c][ptrs[c]])                ptrs[c] += 1                made_progress = True        if not made_progress:            break  # dataset exhausted    return Subset(dataset, chosen)def get_dataset(seed: int):    if DATASET_NAME == "MNIST":        tfm = transforms.Compose([            transforms.ToTensor(),            transforms.Normalize((0.1307,), (0.3081,))        ])        tr_full = datasets.MNIST("./data", train=True, download=True, transform=tfm)        te_full = datasets.MNIST("./data", train=False, download=True, transform=tfm)    elif DATASET_NAME == "CIFAR10":        tfm = transforms.Compose([            transforms.ToTensor(),            transforms.Normalize((0.4914, 0.4822, 0.4465),                                 (0.2023, 0.1994, 0.2010))        ])        tr_full = datasets.CIFAR10("./data", train=True, download=True, transform=tfm)        te_full = datasets.CIFAR10("./data", train=False, download=True, transform=tfm)    elif DATASET_NAME == "OrganAMNIST":        from medmnist import OrganAMNIST        tfm = transforms.Compose([            transforms.ToTensor(),            transforms.Normalize((0.5,), (0.5,))        ])        tr_full = OrganAMNIST(split='train', download=True, transform=tfm, root=SAVE_DIR)        te_full = OrganAMNIST(split='test', download=True, transform=tfm, root=SAVE_DIR)    else:        raise ValueError(f"Unknown DATASET_NAME: {DATASET_NAME}")    tr = _stratified_subset(tr_full, CONFIG["train_limit"], seed, CONFIG["num_classes"])    te = _stratified_subset(te_full, CONFIG["test_limit"], seed + 999, CONFIG["num_classes"])    return tr, tedef init_worker(tr, te):    torch.set_num_threads(1)    torch.set_num_interop_threads(1)    DATA_CACHE["train"] = tr    DATA_CACHE["test"] = tedef seed_worker(worker_id):    # only matters if num_loader_workers > 0    worker_seed = torch.initial_seed() % 2**32    np.random.seed(worker_seed)    random.seed(worker_seed)# ============================================================# 4. MEASUREMENT # ============================================================def compute_soft_mi_nats_from_confusion(soft_confusion: torch.Tensor, pseudocount: float = 0.0) -> float:    conf = soft_confusion    if pseudocount > 0:        conf = conf + pseudocount    total = conf.sum()    if total.item() <= 0:        return 0.0    P_joint = conf / total    P_y = P_joint.sum(dim=1, keepdim=True)    P_yhat = P_joint.sum(dim=0, keepdim=True)    eps = 1e-12    mi = (P_joint * (torch.log(P_joint + eps) - torch.log(P_y + eps) - torch.log(P_yhat + eps))).sum()    return float(mi.item())def measure_state_rigorous(model, loader, criterion, T: float, device: torch.device):    """    Returns dict with:      loss (nats), mi_nats (nats),      S_raw (nats), S_norm ([0,1]), S_var (var of S_norm),      E_var (mean energy variance proxy),      layer_S_means (per-layer mean S_norm)    """    model.eval()    total_loss = 0.0    total_acc = 0    total_samples = 0    agg_S_raw = []    agg_S_norm = []    agg_E_var = []    K = CONFIG["num_classes"]    soft_confusion = torch.zeros(K, K, dtype=torch.float64, device=device)    n_layers = len(model.blocks)    layer_S_norm_sums = np.zeros(n_layers, dtype=np.float64)    with torch.no_grad():        for x, y in loader:            x = x.to(device)            y = y.to(device)            if DATASET_NAME == "OrganAMNIST":                # medmnist often yields shape [B,1]                y = y.squeeze().long()            else:                y = y.long()            bs = int(x.size(0))            logits = model(x, T=T, track_stats=True)            # Loss in nats            loss = criterion(logits, y)            total_loss += float(loss.item()) * bs            total_acc += int((logits.argmax(dim=1) == y).sum().item())            total_samples += bs            # Soft confusion for MI            probs = torch.softmax(logits, dim=-1).to(torch.float64)  # [B,K]            idx = y.view(-1, 1).expand(-1, K)            soft_confusion.scatter_add_(0, idx, probs)            # Attention stats across blocks            block_S_raw = []            block_S_norm = []            block_E_var = []            for li, b in enumerate(model.blocks):                attn = b["attn"]                if attn.batch_S_raw is None or attn.batch_S_norm is None or attn.batch_E_var is None:                    raise RuntimeError("Attention stats missing. Ensure model(..., track_stats=True) was used.")                block_S_raw.append(attn.batch_S_raw)     # [B]                block_S_norm.append(attn.batch_S_norm)   # [B]                block_E_var.append(attn.batch_E_var)     # [B]                layer_S_norm_sums[li] += float(attn.batch_S_norm.sum().item())            # mean across layers per sample            agg_S_raw.extend(torch.stack(block_S_raw).mean(dim=0).cpu().tolist())            agg_S_norm.extend(torch.stack(block_S_norm).mean(dim=0).cpu().tolist())            agg_E_var.extend(torch.stack(block_E_var).mean(dim=0).cpu().tolist())    avg_loss = total_loss / max(1, total_samples)    acc = total_acc / max(1, total_samples)    mi_nats = compute_soft_mi_nats_from_confusion(        soft_confusion,        pseudocount=float(CONFIG["mi_pseudocount"])    )    S_raw_mean = float(np.mean(agg_S_raw)) if agg_S_raw else 0.0    S_norm_mean = float(np.mean(agg_S_norm)) if agg_S_norm else 0.0    S_norm_var = float(np.var(agg_S_norm)) if agg_S_norm else 0.0    E_var_mean = float(np.mean(agg_E_var)) if agg_E_var else 0.0    layer_S_means = layer_S_norm_sums / max(1, total_samples)    return {        "loss": float(avg_loss),        # nats        "acc": float(acc),        "mi_nats": float(mi_nats),      # nats        "S_raw": float(S_raw_mean),     # nats        "S_norm": float(S_norm_mean),   # [0,1]        "S_var": float(S_norm_var),        "E_var": float(E_var_mean),        "layer_S_means": layer_S_means,    }# ============================================================# 5. OPTIMIZER HELPERS # ============================================================def make_adamw_with_decay_groups(model: nn.Module, lr: float, weight_decay: float):    decay_params = []    nodecay_params = []    for name, p in model.named_parameters():        if not p.requires_grad:            continue        # exclude biases, norms, positional embeddings and any 1D params        if p.ndim < 2 or any(s in name.lower() for s in ["bias", "ln", "norm", "pos_emb", "pos_emb"]):            nodecay_params.append(p)        else:            decay_params.append(p)    return optim.AdamW(        [{"params": decay_params, "weight_decay": weight_decay},         {"params": nodecay_params, "weight_decay": 0.0}],        lr=lr    )# ============================================================# 6. WORKER FOR EACH GRID POINT# ============================================================def run_point(task):    i, j, T, wd_val = task    T = max(float(T), 1e-6)    wd_val = float(wd_val)    device = torch.device("cpu")    tr_set, te_set = DATA_CACHE["train"], DATA_CACHE["test"]    num_workers = int(CONFIG["num_loader_workers"])    loader_kwargs = dict(        batch_size=CONFIG["batch_size"],        num_workers=num_workers,        pin_memory=False,        drop_last=False,    )    loader_tr_static = DataLoader(tr_set, shuffle=False, **loader_kwargs)    loader_te_static = DataLoader(te_set, shuffle=False, **loader_kwargs)    res = {        "phi": [], "chi": [], "cv": [], "acc": [],        "dL": [], "Q": [], "dI": [], "dS": [],        "layer_phis": [],    }    for k in range(CONFIG["num_seeds"]):        seed = CONFIG["base_seed"] + 10000 * i + 100 * j + k        torch.manual_seed(seed)        np.random.seed(seed)        random.seed(seed)        model = ThermodynamicViT(CONFIG).to(device)        criterion = nn.CrossEntropyLoss()        optimizer = make_adamw_with_decay_groups(            model=model,            lr=float(CONFIG["lr"]),            weight_decay=wd_val        )        # 1) Initial state on TRAIN        s0 = measure_state_rigorous(model, loader_tr_static, criterion, T, device)        # 2) Train with deterministic shuffle order        model.train()        g = torch.Generator()        g.manual_seed(seed)        loader_tr_shuff = DataLoader(            tr_set,            shuffle=True,            generator=g,            worker_init_fn=seed_worker if num_workers > 0 else None,            **loader_kwargs        )        for _ in range(CONFIG["epochs"]):            for x, y in loader_tr_shuff:                x = x.to(device)                y = y.to(device)                if DATASET_NAME == "OrganAMNIST":                    y = y.squeeze().long()                else:                    y = y.long()                optimizer.zero_grad(set_to_none=True)                out = model(x, T=T, track_stats=False)                loss = criterion(out, y)                loss.backward()                optimizer.step()        # 3) Final state on TRAIN and TEST        sf = measure_state_rigorous(model, loader_tr_static, criterion, T, device)        st = measure_state_rigorous(model, loader_te_static, criterion, T, device)        # 4) First-law style quantities (all nats)        dL = s0["loss"] - sf["loss"]              # nats        dS_raw = s0["S_raw"] - sf["S_raw"]        # nats        Q = T * dS_raw                            # nats (T is dimensionless)        dI = sf["mi_nats"] - s0["mi_nats"]        # nats        # Phase metrics from normalized entropy (TEST)        phi = 1.0 - st["S_norm"]        chi = st["S_var"]        cv = st["E_var"] / (T**2 + 1e-6)        layer_phis_run = (1.0 - st["layer_S_means"]).tolist()        res["dL"].append(float(dL))        res["Q"].append(float(Q))        res["dI"].append(float(dI))        res["dS"].append(float(dS_raw))        res["phi"].append(float(phi))        res["chi"].append(float(chi))        res["cv"].append(float(cv))        res["acc"].append(float(st["acc"]))        res["layer_phis"].append(layer_phis_run)    # Aggregate    scalar_keys = [k for k in res.keys() if k != "layer_phis"]    avg_res = {k: float(np.mean(res[k])) for k in scalar_keys}    avg_res["layer_phis"] = np.mean(res["layer_phis"], axis=0).tolist()    return (i, j, avg_res)# ============================================================# 7. MAIN# ============================================================def main():    try:        multiprocessing.set_start_method("spawn", force=True)    except Exception:        pass    tr, te = get_dataset(CONFIG["base_seed"])    tasks = [(i, j, TEMPS[i], WEIGHT_DECAYS[j])             for i in range(len(TEMPS))             for j in range(len(WEIGHT_DECAYS))]    print(f"--- Running {DATASET_NAME} Thermodynamics ---")    print(f"Grid: {len(TEMPS)} x {len(WEIGHT_DECAYS)} | Pool workers: {CONFIG['pool_workers']}")    print(f"Seeds per point: {CONFIG['num_seeds']}")    with multiprocessing.Pool(        processes=CONFIG["pool_workers"],        initializer=init_worker,        initargs=(tr, te)    ) as pool:        results = list(tqdm(pool.imap(run_point, tasks), total=len(tasks)))    shape = (len(TEMPS), len(WEIGHT_DECAYS))    sample_res = results[0][2]    scalar_keys = [k for k in sample_res.keys() if k != "layer_phis"]    n_layers = len(sample_res["layer_phis"])    data = {k: np.zeros(shape, dtype=np.float64) for k in scalar_keys}    layer_grids = [np.zeros(shape, dtype=np.float64) for _ in range(n_layers)]    for i, j, r in results:        for k in scalar_keys:            data[k][i, j] = r[k]        for l in range(n_layers):            layer_grids[l][i, j] = r["layer_phis"][l]    # First-law RHS in nats    data["RHS_nats"] = data["Q"] + data["dI"]    # Pack output    clean_config = {k: (v if v is not None else "None") for k, v in CONFIG.items()}    out = {        "TEMPS": TEMPS,        "WEIGHT_DECAYS": WEIGHT_DECAYS,        "config": clean_config,        **{f"{k}_grid": v for k, v in data.items()},    }    for l in range(n_layers):        out[f"phi_layer_{l}_grid"] = layer_grids[l]    # MATLAB-friendly aliases    out["Q_attn_grid"] = data["Q"]    out["dL_train_grid"] = data["dL"]    out["dI_soft_grid"] = data["dI"]    out["acc_test_grid"] = data["acc"]    out["phi_attn_grid"] = data["phi"]    out["chi_attn_grid"] = data["chi"]    out["cv_attn_grid"] = data["cv"]    out["RHS_attn_grid"] = data["RHS_nats"]    mat_path = os.path.join(SAVE_DIR, f"{EXPERIMENT_NAME}.mat")    scipy.io.savemat(mat_path, out)    print(f"Saved MATLAB: {mat_path}")    pkl_path = os.path.join(SAVE_DIR, f"{EXPERIMENT_NAME}.pkl")    with open(pkl_path, "wb") as f:        pickle.dump(out, f)    print(f"Saved PKL: {pkl_path}")if __name__ == "__main__":    main()